/**
 * detectarZonaClimatica(altitud, lat, lon)
 * Devuelve {zonaId, label} compatibles con las zonas del calendario de siembra.
 */
function detectarZonaClimatica(altitud, lat, lon) {
  if (lat < 30)
    return {zonaId:'subtropical', label:'Subtropical — Canarias'};
  if (lat > 35 && lat < 36 && lon > -6 && lon < -1)
    return {zonaId:'subtropical', label:'Subtropical — Ceuta/Melilla'};
  if (altitud > 1000)
    return {zonaId:'continental_fria', label:'Alta montaña (>1000 m)'};
  if (altitud >= 600 && lat > 41)
    return {zonaId:'continental_fria', label:'Montaña media norte'};
  if (altitud >= 600)
    return {zonaId:'continental_calida', label:'Montaña media sur'};
  if (altitud >= 200 && lat > 41)
    return {zonaId:'continental_fria', label:'Interior norte'};
  if (altitud >= 200)
    return {zonaId:'continental_calida', label:'Interior sur'};
  if (lat < 38)
    return {zonaId:'semiarida', label:'Semiárida'};
  if (lon < -2)
    return {zonaId:'atlantica', label:'Atlántica'};
  return {zonaId:'mediterranea', label:'Mediterránea costera'};
}

/**
 * initBuscadorMunicipio(zoneSelectId, onZoneSet)
 * Inicializa el buscador de municipio en la página actual.
 * Requiere que existan en el DOM: #muni-input, #muni-btn, #muni-sugerencias, #muni-estado
 * @param {string|null} zoneSelectId - ID del <select> de zona a rellenar automáticamente (null si no hay)
 * @param {function|null} onZoneSet  - Callback(zonaId, label, municipio) tras seleccionar
 */
function nombreNatural(nombre) {
  var m = nombre.match(/^(.+)\s+\((La|El|Los|Las|L'|Els|Les|A|O|Es|As|Sa|Ses|Os|la|el|els|les|a|o|es|as|sa|ses|os)\)$/);
  if (m) return m[2].charAt(0).toUpperCase() + m[2].slice(1) + ' ' + m[1];
  return nombre;
}

function initBuscadorMunicipio(zoneSelectId, onZoneSet) {
  var muniSeleccionado = null;
  var input  = document.getElementById('muni-input');
  var btn    = document.getElementById('muni-btn');
  var lista  = document.getElementById('muni-sugerencias');
  var estado = document.getElementById('muni-estado');
  if (!input) return;

  function setEst(msg, color) {
    if (estado) { estado.textContent = msg; estado.style.color = color || 'var(--texto-sec)'; }
  }
  function nm(s) {
    return s.toLowerCase().normalize('NFD').replace(/[̀-ͯ]/g, '');
  }
  function buscar(q) {
    var qOriginal = q.trim();
    var qn = nm(qOriginal);
    // Si la query empieza con artículo, prueba también la versión con el artículo movido al final
    var match = qOriginal.match(/^(la|el|los|las)\s+(.+)$/i);
    var qnAlt = match ? nm(match[2] + ' (' + match[1] + ')') : null;
    if (!qn) return [];
    function rango(m) {
      var nombreNorm = nm(m.nombre);
      var nombreNatNorm = nm(nombreNatural(m.nombre));
      if (nombreNorm === qn || nombreNatNorm === qn) return 0;
      if (nombreNorm.startsWith(qn) || nombreNatNorm.startsWith(qn)) return 1;
      if (qnAlt && (nombreNorm === qnAlt || nombreNatNorm === qnAlt)) return 0;
      if (qnAlt && (nombreNorm.startsWith(qnAlt) || nombreNatNorm.startsWith(qnAlt))) return 1;
      return 2;
    }
    return MUNICIPIOS.filter(function(m){
      var nombreNorm = nm(m.nombre);
      var nombreNatNorm = nm(nombreNatural(m.nombre));
      return nombreNorm.includes(qn) || nombreNatNorm.includes(qn) ||
             (qnAlt && (nombreNorm.includes(qnAlt) || nombreNatNorm.includes(qnAlt)));
    }).sort(function(a,b){ return rango(a) - rango(b); }).slice(0,8);
  }
  function mostrar(res) {
    lista.innerHTML = '';
    if (!res.length) { setEst('No se encontró ningún municipio con ese nombre.','#C2410C'); lista.style.display='none'; return; }
    res.forEach(function(m) {
      var li = document.createElement('li');
      li.textContent = nombreNatural(m.nombre) + ' (' + m.provincia + ') — ' + m.altitud + ' m';
      li.style.cssText = 'padding:10px 14px;cursor:pointer;font-size:14px;border-bottom:1px solid var(--borde);';
      li.addEventListener('mouseenter', function(){ li.style.background='var(--fondo)'; });
      li.addEventListener('mouseleave', function(){ li.style.background='white'; });
      li.addEventListener('click', function(){ sel(m); });
      lista.appendChild(li);
    });
    lista.style.display = 'block';
  }
  function sel(m) {
    muniSeleccionado = m;
    lista.style.display = 'none';
    input.value = nombreNatural(m.nombre) + ' (' + m.provincia + ')';
    var r = detectarZonaClimatica(m.altitud, m.lat, m.lon);
    if (zoneSelectId) {
      var s = document.getElementById(zoneSelectId);
      if (s) s.value = r.zonaId;
    }
    setEst('✓ Tu zona climática: ' + r.label, 'var(--verde)');
    if (onZoneSet) onZoneSet(r.zonaId, r.label, m);
  }
  function ejecutar() {
    if (muniSeleccionado) { sel(muniSeleccionado); return; }
    var q = input.value.trim();
    if (!q) return;
    var res = buscar(q);
    if (res.length === 1) { sel(res[0]); }
    else { mostrar(res); if (res.length) setEst('Elige tu municipio de la lista.','var(--texto-sec)'); }
  }
  input.addEventListener('input', function() {
    muniSeleccionado = null;
    var q = input.value.trim();
    if (q.length >= 3) mostrar(buscar(q)); else lista.style.display='none';
  });
  if (btn) { btn.addEventListener('click', ejecutar); }
  input.addEventListener('keydown', function(e){ if (e.key==='Enter') ejecutar(); });
  document.addEventListener('click', function(e){ if (!e.target.closest('#muni-buscador')) lista.style.display='none'; });
}
